function animateCounter(t,e,r=1500){const n=performance.now();requestAnimationFrame(function o(a){const s=a-n,c=Math.min(s/r,1),u=1-Math.pow(1-c,3),i=Math.floor(u*e);t.textContent=i,c<1?requestAnimationFrame(o):t.textContent=e})}const statNumbers=document.querySelectorAll(".stat-number"),counterObserver=new IntersectionObserver(t=>{t.forEach(t=>{if(t.isIntersecting){const e=t.target,r=parseInt(e.getAttribute("data-target"),10);animateCounter(e,r),counterObserver.unobserve(e)}})},{threshold:.5});statNumbers.forEach(t=>counterObserver.observe(t));